#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long n;
        scanf("%lld", &n);
        long long sum_even = 0;
        long long counter = 1;
        while (counter <= n) {
            if (counter % 2 == 0) {
                sum_even += counter;
            }
            counter++;
        }
        printf("%lld\n", sum_even);
    }
    return 0;
}

