import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        n = int(next(it))
        sum_even = 0
        counter = 1
        while counter <= n:
            if counter % 2 == 0:
                sum_even += counter
            counter += 1
        out.append(str(sum_even))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

